#include <stdio.h>
#include <string.h>
#include <stdbool.h>

bool isIsomorphic(char *s, char *t) {
    int len = strlen(s);
    if (len != strlen(t)) return false;

    char mapST[256] = {0};  // mapping from s -> t
    char mapTS[256] = {0};  // mapping from t -> s

    for (int i = 0; i < len; i++) {
        unsigned char c1 = s[i];
        unsigned char c2 = t[i];

        // Check mapping s -> t
        if (mapST[c1] == 0)
            mapST[c1] = c2;
        else if (mapST[c1] != c2)
            return false;

        // Check mapping t -> s
        if (mapTS[c2] == 0)
            mapTS[c2] = c1;
        else if (mapTS[c2] != c1)
            return false;
    }
    return true;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        char s[100001], t[100001];
        scanf("%s %s", s, t);
        if (isIsomorphic(s, t)) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

