#include <iostream>
#include <string>
#include <unordered_map>

bool isIsomorphic(const std::string &s, const std::string &t) {
    if (s.length() != t.length()) return false;

    std::unordered_map<char, char> mapST, mapTS;

    for (size_t i = 0; i < s.length(); i++) {
        char c1 = s[i];
        char c2 = t[i];

        // Check mapping s -> t
        if (mapST.count(c1)) {
            if (mapST[c1] != c2) return false;
        } else {
            mapST[c1] = c2;
        }

        // Check mapping t -> s
        if (mapTS.count(c2)) {
            if (mapTS[c2] != c1) return false;
        } else {
            mapTS[c2] = c1;
        }
    }
    return true;
}

int main() {
    int T;
    std::cin >> T;
    for (int i = 0; i < T; i++) {
        std::string s, t;
        std::cin >> s >> t;
        if (isIsomorphic(s, t)) std::cout << "YES\n";
        else std::cout << "NO\n";
    }
    return 0;
}

